// Validación y clasificación (contingencia del Riesgo R1 del APF1)
// Reutiliza la misma lógica de negocio que la app (metrics.service.js).
const EVALS = {
  SIST101: [['pc1',0.2],['pc2',0.2],['proyectoFinal',0.3],['examenFinal',0.3]],
  SIST102: [['avance1',0.15],['avance2',0.15],['proyectoFinal',0.3],['examenFinal',0.4]],
  SIST103: [['laboratorio',0.15],['pc1',0.2],['pc2',0.2],['proyectoBD',0.45]],
  SIST104: [['avance1',0.1],['avance2',0.2],['sustentacion',0.3],['informeFinal',0.4]],
  SIST105: [['prototipo1',0.15],['prototipo2',0.2],['pc',0.25],['examenFinal',0.4]],
  SIST106: [['ejercicios',0.1],['pc1',0.2],['pc2',0.2],['proyecto',0.5]],
  SIST107: [['participacion',0.1],['trabajoParcial',0.2],['trabajoFinal',0.3],['examen',0.4]],
  SIST108: [['foros',0.1],['pc',0.2],['trabajoAplicativo',0.3],['examenFinal',0.4]],
  SIST109: [['talleres',0.1],['pc1',0.2],['pc2',0.25],['proyectoWeb',0.45]],
  EDUC201: [['avanceTeorico',0.15],['avanceMetodologia',0.15],['informeFinal',0.3],['examen',0.4]],
  EDUC202: [['practicas',0.15],['pc1',0.2],['pc2',0.25],['examenFinal',0.4]],
  EDUC203: [['foros',0.1],['trabajoGrupal',0.2],['pc',0.3],['examenFinal',0.4]],
  EDUC204: [['avance1',0.15],['avance2',0.15],['disenoFinal',0.3],['examen',0.4]],
  EDUC205: [['practicas',0.1],['proyectoAula',0.2],['pc',0.3],['examenFinal',0.4]],
  EDUC206: [['trabajoParcial',0.2],['trabajoFinal',0.25],['examenParcial',0.25],['examenFinal',0.3]],
  EDUC207: [['participacion',0.1],['trabajoAplicativo',0.2],['pc',0.3],['examenFinal',0.4]],
  EDUC208: [['avanceCap1',0.15],['avanceCap2',0.15],['borradorTesis',0.3],['sustentacion',0.4]],
  EDUC209: [['debates',0.1],['ensayo',0.2],['pc',0.3],['examenFinal',0.4]],
};
const ROUND_THRESHOLD = 11.45;
const MIN_APPROVAL = 12;

function calcRiesgo(promedio, asistencia, dias) {
  if (promedio < 8 || asistencia < 50 || dias > 21) return 'CRITICO';
  if (promedio < 10 || asistencia < 65 || dias > 14) return 'ALTO';
  if (promedio < 12 || asistencia < 75) return 'MEDIO';
  return 'BAJO';
}

const out = [];
for (const item of $input.all()) {
  const r = item.json;
  const errores = [];

  const codigo = String(r.codigo || '').trim();
  const nombre = String(r.nombre || '').trim();
  const cursoId = String(r.curso_id || '').trim();
  const docente = String(r.docente_codigo || '').trim();
  const asistencia = Number(r.asistencia);
  const dias = Number(r.actividad_dias);

  if (!codigo) errores.push('codigo vacío');
  if (!nombre) errores.push('nombre vacío');
  if (!EVALS[cursoId]) errores.push(`curso_id desconocido: ${cursoId}`);
  if (!/^C\d+$/.test(docente)) errores.push(`docente_codigo inválido: ${docente}`);
  if (!(asistencia >= 0 && asistencia <= 100)) errores.push(`asistencia fuera de rango: ${r.asistencia}`);
  if (!(dias >= 0 && dias <= 120)) errores.push(`actividad_dias fuera de rango: ${r.actividad_dias}`);

  const notas = {};
  let promedio = 0;
  if (EVALS[cursoId]) {
    for (const [key, peso] of EVALS[cursoId]) {
      const raw = r[key];
      if (raw === undefined || raw === null || String(raw).trim() === '') {
        notas[key] = null; // evaluación pendiente
        continue;
      }
      const n = Number(raw);
      if (!(n >= 0 && n <= 20)) {
        errores.push(`nota ${key} fuera de rango 0-20: ${raw}`);
        continue;
      }
      notas[key] = n;
      promedio += n * peso;
    }
  }
  promedio = Number(promedio.toFixed(2));
  const notaFinal = promedio >= ROUND_THRESHOLD && promedio < MIN_APPROVAL ? MIN_APPROVAL : promedio;

  if (errores.length > 0) {
    out.push({ json: { valido: false, codigo: codigo || '(sin código)', errores, original: r } });
    continue;
  }

  out.push({
    json: {
      valido: true,
      row: {
        codigo,
        nombre,
        email: String(r.email || `${codigo.toLowerCase()}@utp.edu.pe`).trim(),
        carrera: String(r.carrera || '').trim(),
        ciclo: String(r.ciclo || '').trim(),
        curso_id: cursoId,
        docente_codigo: docente,
        asistencia,
        actividad_dias: dias,
        notas,
        promedio,
        nota_final: Number(notaFinal.toFixed(2)),
        riesgo: calcRiesgo(promedio, asistencia, dias),
      },
    },
  });
}
return out;
